/**
 * Custom Hook for Invoice Form Management
 * 
 * Manages invoice form state, validation, and submission logic.
 */

import { useState, useMemo, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { createInvoiceSchema } from '@/shared/utils/validation/invoiceSchemas.js';
import { validateInvoiceForm } from '@/shared/utils/validation/helpers.js';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import { logger } from '@/shared/utils/logger.js';

const INITIAL_INVOICE_DATA = {
  firstName: '',
  lastName: '',
  customerEmail: '',
  customerPhoneCountryCode: '+233',
  customerPhone: '',
  payee_note: 'payload',
  description: '',
  provider: '',
  channel: 'MOMO',
  bankAccountNumber: '',
  paymentType: 'INVOICE',
  mission: '',
  missionCountryCode: '+233',
  items: [
    { description: '', quantity: '', unitPrice: '', total: 0 }
  ],
  subtotal: 0,
  taxAmount: 0,
  total: 0,
  currency: 'GHS',
  saveDraft: true,
  sendInvoice: false
};

export const useInvoiceForm = () => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const [invoiceData, setInvoiceData] = useState(INITIAL_INVOICE_DATA);
  const [formErrors, setFormErrors] = useState({});
  const [itemErrors, setItemErrors] = useState({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  const validationSchema = useMemo(() => createInvoiceSchema(t), [t]);

  const handleInputChange = useCallback((e) => {
    const { name, value, type, checked } = e.target;

    // Automatically remove leading zero from phone numbers
    if ((name === 'customerPhone' || name === 'mission') && value && value.startsWith('0')) {
      setInvoiceData(prev => ({
        ...prev,
        [name]: value.substring(1)
      }));
      // Clear error for this field
      if (formErrors[name]) {
        setFormErrors(prev => {
          const next = { ...prev };
          delete next[name];
          return next;
        });
      }
      return;
    }

    setInvoiceData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));

    // Clear error for this field
    if (formErrors[name]) {
      setFormErrors(prev => {
        const next = { ...prev };
        delete next[name];
        return next;
      });
    }
  }, [formErrors]);

  const handleItemChange = useCallback((index, field, value) => {
    setInvoiceData(prev => {
      const newItems = [...prev.items];
      newItems[index][field] = value;

      // Recalculate total only if quantity or unit price changes
      if (field === 'quantity' || field === 'unitPrice') {
        const quantity = parseFloat(newItems[index].quantity) || 0;
        const unitPrice = parseFloat(newItems[index].unitPrice) || 0;
        newItems[index].total = quantity * unitPrice;
      }

      // Recalculate subtotal and total
      const subtotal = newItems.reduce((sum, item) => sum + (parseFloat(item.total) || 0), 0);

      return {
        ...prev,
        items: newItems,
        subtotal: subtotal,
        total: subtotal
      };
    });

    // Clear error for this item field
    const errorKey = `items.${index}.${field}`;
    if (itemErrors[errorKey]) {
      setItemErrors(prev => {
        const next = { ...prev };
        delete next[errorKey];
        return next;
      });
    }
  }, [itemErrors]);

  const addNewItem = useCallback(() => {
    setInvoiceData(prev => ({
      ...prev,
      items: [...prev.items, { description: '', quantity: '', unitPrice: '', total: 0 }]
    }));
  }, []);

  const removeItem = useCallback((index) => {
    setInvoiceData(prev => {
      const newItems = prev.items.filter((_, i) => i !== index);
      const subtotal = newItems.reduce((sum, item) => sum + (parseFloat(item.total) || 0), 0);
      return {
        ...prev,
        items: newItems,
        subtotal: subtotal,
        total: subtotal
      };
    });
  }, []);

  const validateForm = useCallback(() => {
    const validationResult = validateInvoiceForm(
      invoiceData,
      validationSchema,
      setFormErrors,
      setItemErrors,
      showError,
      t
    );
    return validationResult.success;
  }, [invoiceData, validationSchema, showError, t]);

  const resetForm = useCallback(() => {
    // Deep clone to ensure complete reset
    const resetData = {
      ...INITIAL_INVOICE_DATA,
      items: [{ description: '', quantity: '', unitPrice: '', total: 0 }]
    };
    setInvoiceData(resetData);
    setFormErrors({});
    setItemErrors({});
  }, []);

  return {
    invoiceData,
    setInvoiceData,
    formErrors,
    setFormErrors,
    itemErrors,
    isSubmitting,
    setIsSubmitting,
    handleInputChange,
    handleItemChange,
    addNewItem,
    removeItem,
    validateForm,
    resetForm,
  };
};

