/**
 * Custom Hook for Loading Invoice Profile Data
 * 
 * Handles loading user profile data to pre-fill invoice form fields.
 */

import { useEffect } from 'react';
import { logger } from '@/shared/utils/logger.js';

/**
 * Normalize phone number to format expected by invoice form
 * Returns just the local number (without country code) since missionCountryCode is separate
 */
const normalizePhoneForInvoice = (phoneNumber) => {
  if (!phoneNumber) { return ''; }

  let phoneStr = String(phoneNumber).trim();

  // Remove + sign if present
  if (phoneStr.startsWith('+')) {
    phoneStr = phoneStr.substring(1);
  }

  // Remove country code (233) if present
  if (phoneStr.startsWith('233')) {
    phoneStr = phoneStr.substring(3);
  }

  // Remove leading 0 if present (local numbers often start with 0)
  if (phoneStr.startsWith('0')) {
    phoneStr = phoneStr.substring(1);
  }

  return phoneStr;
};

/**
 * Extract phone number from various data sources
 */
const extractPhoneNumber = (data) => {
  return data?.phone_number ||
    data?.phone ||
    data?.phoneNumber ||
    data?.user?.phone_number ||
    data?.user?.phone ||
    '';
};

export const useInvoiceProfile = (setInvoiceData) => {
  // First check localStorage userData
  const userDataStr = localStorage.getItem('userData');
  let phoneNumber = '';

  if (userDataStr) {
    try {
      const userData = JSON.parse(userDataStr);
      phoneNumber = extractPhoneNumber(userData);
      logger.debug('Phone from localStorage', { phoneNumber });
    } catch (e) {
      logger.warn('Failed to parse userData from localStorage', { error: e });
    }
  }

  // Set phone from localStorage if available
  useEffect(() => {
    if (phoneNumber) {
      const normalizedPhone = normalizePhoneForInvoice(phoneNumber);
      logger.debug('Normalized phone for invoice from localStorage', { normalizedPhone });

      setInvoiceData(prev => ({
        ...prev,
        mission: normalizedPhone
      }));
    }
  }, [phoneNumber, setInvoiceData]);

  return { isLoading: false };
};

