/**
 * Invoice PDF Generator Utility
 * 
 * Handles PDF generation for invoices using jsPDF library.
 * Provides a clean, reusable function for generating invoice PDFs.
 */

import jsPDF from 'jspdf';
import { CURRENCIES } from '../constants/invoicing-constants.js';
import { logger } from '@/shared/utils/logger.js';

/**
 * Get currency symbol for PDF (handles special characters)
 * @param {string} currencyCode - Currency code (e.g., 'GHS', 'USD')
 * @returns {string} PDF-safe currency symbol or code
 */
const getCurrencySymbolForPDF = (currencyCode) => {
  const currency = CURRENCIES.find(c => c.code === currencyCode);
  if (!currency) { return 'GHS'; }

  // Map special characters to PDF-safe alternatives
  const symbolMap = {
    'GH₵': 'GHS',
    '₵': 'GHS',
    '$': '$',
    '€': 'EUR',
    '£': 'GBP'
  };

  return symbolMap[currency.symbol] || currency.code;
};

/**
 * Load image and convert to base64 for PDF
 * @param {string} imagePath - Path to the image
 * @returns {Promise<string>} Base64 data URL of the image
 */
const loadImageAsBase64 = (imagePath) => {
  return new Promise((resolve, reject) => {
    if (typeof window === 'undefined') {
      reject(new Error('Not in browser environment'));
      return;
    }

    const img = new Image();
    img.crossOrigin = 'anonymous';

    img.onload = function () {
      try {
        const canvas = document.createElement('canvas');
        canvas.width = this.width;
        canvas.height = this.height;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(this, 0, 0);
        const imgData = canvas.toDataURL('image/png');
        resolve(imgData);
      } catch (error) {
        reject(error);
      }
    };

    img.onerror = () => {
      reject(new Error(`Failed to load image: ${imagePath}`));
    };

    img.src = imagePath;
  });
};

/**
 * Generate PDF document and return as blob URL for preview
 * @param {Object} invoiceData - Invoice data object
 * @param {boolean} returnBlob - If true, returns blob URL instead of downloading
 * @returns {Promise<string|boolean>} Blob URL if returnBlob is true, otherwise boolean
 * @throws {Error} If PDF generation fails
 */
export const generateInvoicePDF = async (invoiceData, returnBlob = false) => {
  try {
    logger.debug('Generating invoice PDF', { invoiceData });

    // Create new PDF document
    const pdf = new jsPDF({
      orientation: 'portrait',
      unit: 'mm',
      format: 'a4'
    });

    const pageWidth = pdf.internal.pageSize.getWidth();
    const pageHeight = pdf.internal.pageSize.getHeight();
    const margin = 20;
    const contentWidth = pageWidth - (margin * 2);
    let yPosition = 20;

    // Get currency symbol for PDF
    const currencySymbol = getCurrencySymbolForPDF(invoiceData.currency);
    const invoiceNumber = `INV-${Date.now().toString().slice(-8)}`;
    const currentDate = new Date().toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });

    // Professional Header
    const headerTopMargin = 15;
    yPosition = headerTopMargin;

    // Try to add logo image
    let logoAdded = false;
    let logoWidth = 0;
    let logoHeight = 0;

    try {
      const logoPath = '/Asset 2@1.5x (1).png';

      if (typeof window !== 'undefined') {
        const imgData = await loadImageAsBase64(logoPath);
        const img = new Image();
        img.src = imgData;
        await new Promise((resolve) => {
          img.onload = resolve;
        });

        // Professional logo sizing
        const maxLogoWidth = 80;
        const maxLogoHeight = 35;
        const aspectRatio = img.width / img.height;

        if (aspectRatio > 1) {
          logoWidth = Math.min(maxLogoWidth, maxLogoHeight * aspectRatio);
          logoHeight = logoWidth / aspectRatio;
        } else {
          logoHeight = Math.min(maxLogoHeight, maxLogoWidth / aspectRatio);
          logoWidth = logoHeight * aspectRatio;
        }

        // Position logo at top left
        pdf.addImage(imgData, 'PNG', margin, yPosition, logoWidth, logoHeight);
        logoAdded = true;
      }
    } catch (error) {
      logger.warn('Could not load logo image for PDF', { error });
    }

    // Invoice title
    const invoiceText = 'INVOICE';
    pdf.setFontSize(40);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(17, 24, 39);

    const invoiceTextWidth = pdf.getTextWidth(invoiceText);
    const invoiceX = pageWidth - margin - invoiceTextWidth;
    const invoiceTextY = logoAdded ? yPosition + logoHeight / 2 + 5 : yPosition + 8;

    pdf.text(invoiceText, invoiceX, invoiceTextY);

    yPosition = logoAdded ? yPosition + logoHeight + 12 : yPosition + 15;

    // Invoice Metadata Table - Compact
    const metaTableY = yPosition;
    const metaTableHeight = 12;
    const metaTableWidth = contentWidth;

    // Table background
    pdf.setFillColor(249, 250, 251);
    pdf.rect(margin, metaTableY - 3, metaTableWidth, metaTableHeight, 'F');

    // Table borders
    pdf.setDrawColor(229, 231, 235);
    pdf.setLineWidth(0.2);
    pdf.rect(margin, metaTableY - 3, metaTableWidth, metaTableHeight, 'S');
    pdf.line(margin + metaTableWidth / 2, metaTableY - 3, margin + metaTableWidth / 2, metaTableY - 3 + metaTableHeight);

    // Left column - Invoice Number
    pdf.setFontSize(8);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(107, 114, 128);
    pdf.text('Invoice #:', margin + 4, metaTableY + 1);
    pdf.setFont('helvetica', 'normal');
    pdf.setTextColor(17, 24, 39);
    pdf.text(invoiceNumber, margin + 4, metaTableY + 6);

    // Right column - Date
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(107, 114, 128);
    pdf.text('Date:', margin + metaTableWidth / 2 + 4, metaTableY + 1);
    pdf.setFont('helvetica', 'normal');
    pdf.setTextColor(17, 24, 39);
    pdf.text(currentDate, margin + metaTableWidth / 2 + 4, metaTableY + 6);

    yPosition = metaTableY + metaTableHeight + 10;

    // Customer and Payment Info Tables - Compact
    const leftColumnX = margin;
    const rightColumnX = pageWidth / 2 + 5;
    const sectionStartY = yPosition;
    const sectionHeight = 46;
    const sectionWidth = 85;

    // Bill To Table
    const billToTableY = yPosition;

    // Table header - smaller
    pdf.setFillColor(5, 150, 105);
    pdf.rect(leftColumnX, billToTableY - 5, sectionWidth, 5, 'F');

    pdf.setFontSize(8);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(255, 255, 255);
    pdf.text('BILL TO', leftColumnX + 4, billToTableY - 1);

    // Table body
    pdf.setFillColor(255, 255, 255);
    pdf.setDrawColor(229, 231, 235);
    pdf.setLineWidth(0.2);
    pdf.rect(leftColumnX, billToTableY, sectionWidth, sectionHeight, 'FD');

    // Table rows - compact
    let tableRowY = billToTableY + 4;

    // Name row
    pdf.setDrawColor(229, 231, 235);
    pdf.setLineWidth(0.15);
    pdf.line(leftColumnX, tableRowY + 5, leftColumnX + sectionWidth, tableRowY + 5);

    pdf.setFontSize(7);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(107, 114, 128);
    pdf.text('Name:', leftColumnX + 4, tableRowY);
    pdf.setFontSize(9);
    pdf.setFont('helvetica', 'normal');
    pdf.setTextColor(17, 24, 39);
    const nameText = pdf.splitTextToSize(`${invoiceData.firstName} ${invoiceData.lastName}`, sectionWidth - 10);
    pdf.text(nameText, leftColumnX + 4, tableRowY + 5);
    tableRowY += 9;

    // Email row
    if (invoiceData.customerEmail) {
      pdf.line(leftColumnX, tableRowY + 5, leftColumnX + sectionWidth, tableRowY + 5);
      pdf.setFontSize(7);
      pdf.setFont('helvetica', 'bold');
      pdf.setTextColor(107, 114, 128);
      pdf.text('Email:', leftColumnX + 4, tableRowY);
      pdf.setFontSize(8);
      pdf.setFont('helvetica', 'normal');
      pdf.setTextColor(17, 24, 39);
      const emailText = pdf.splitTextToSize(invoiceData.customerEmail, sectionWidth - 10);
      pdf.text(emailText, leftColumnX + 4, tableRowY + 5);
      tableRowY += 9;
    }

    // Phone row
    pdf.line(leftColumnX, tableRowY + 5, leftColumnX + sectionWidth, tableRowY + 5);
    pdf.setFontSize(7);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(107, 114, 128);
    pdf.text('Phone:', leftColumnX + 4, tableRowY);
    pdf.setFontSize(8);
    pdf.setFont('helvetica', 'normal');
    pdf.setTextColor(17, 24, 39);
    const phoneText = pdf.splitTextToSize(`${invoiceData.customerPhoneCountryCode} ${invoiceData.customerPhone}`, sectionWidth - 10);
    pdf.text(phoneText, leftColumnX + 4, tableRowY + 5);

    // Payment Details Table
    const paymentTableY = sectionStartY;

    // Table header - smaller
    pdf.setFillColor(5, 150, 105);
    pdf.rect(rightColumnX, paymentTableY - 5, sectionWidth, 5, 'F');

    pdf.setFontSize(8);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(255, 255, 255);
    pdf.text('PAYMENT DETAILS', rightColumnX + 4, paymentTableY - 1);

    // Table body
    pdf.setFillColor(255, 255, 255);
    pdf.setDrawColor(229, 231, 235);
    pdf.setLineWidth(0.2);
    pdf.rect(rightColumnX, paymentTableY, sectionWidth, sectionHeight, 'FD');

    // Table rows - compact
    tableRowY = paymentTableY + 4;

    // Provider row
    pdf.setDrawColor(229, 231, 235);
    pdf.setLineWidth(0.15);
    pdf.line(rightColumnX, tableRowY + 5, rightColumnX + sectionWidth, tableRowY + 5);

    pdf.setFontSize(7);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(107, 114, 128);
    pdf.text('Provider:', rightColumnX + 4, tableRowY);
    pdf.setFontSize(8);
    pdf.setFont('helvetica', 'normal');
    pdf.setTextColor(17, 24, 39);
    const providerText = pdf.splitTextToSize(invoiceData.provider, sectionWidth - 10);
    pdf.text(providerText, rightColumnX + 4, tableRowY + 5);
    tableRowY += 9;

    // Currency row
    pdf.line(rightColumnX, tableRowY + 5, rightColumnX + sectionWidth, tableRowY + 5);
    pdf.setFontSize(7);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(107, 114, 128);
    pdf.text('Currency:', rightColumnX + 4, tableRowY);
    pdf.setFontSize(8);
    pdf.setFont('helvetica', 'normal');
    pdf.setTextColor(17, 24, 39);
    pdf.text(invoiceData.currency, rightColumnX + 4, tableRowY + 5);
    tableRowY += 9;

    // Channel row
    pdf.line(rightColumnX, tableRowY + 5, rightColumnX + sectionWidth, tableRowY + 5);
    pdf.setFontSize(7);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(107, 114, 128);
    pdf.text('Channel:', rightColumnX + 4, tableRowY);
    pdf.setFontSize(8);
    pdf.setFont('helvetica', 'normal');
    pdf.setTextColor(17, 24, 39);
    pdf.text((invoiceData.channel || 'MOMO').toString().toUpperCase(), rightColumnX + 4, tableRowY + 5);

    yPosition = sectionStartY + sectionHeight + 12;

    // Description Table (if description exists) - Keep together on one page
    if (invoiceData.description) {
      // Calculate description height first
      pdf.setFontSize(9);
      const descLines = pdf.splitTextToSize(invoiceData.description, contentWidth - 8);
      const descTextHeight = descLines.length * 4;
      const descTableHeight = Math.max(18, descTextHeight + 6);
      const totalDescHeight = descTableHeight + 5 + 2; // Header + body + spacing

      // Check if description fits on current page, if not move to next page
      if (yPosition + totalDescHeight > pageHeight - 100) {
        pdf.addPage();
        yPosition = margin;
      }

      const descTableY = yPosition;

      // Table header - compact
      pdf.setFillColor(249, 250, 251);
      pdf.rect(margin, descTableY - 4, contentWidth, 5, 'F');

      pdf.setFontSize(7);
      pdf.setFont('helvetica', 'bold');
      pdf.setTextColor(107, 114, 128);
      pdf.text('DESCRIPTION', margin + 4, descTableY - 0.5);

      // Table body
      pdf.setFillColor(255, 255, 255);
      pdf.setDrawColor(229, 231, 235);
      pdf.setLineWidth(0.2);
      pdf.rect(margin, descTableY + 1, contentWidth, descTableHeight, 'FD');

      pdf.setFontSize(9);
      pdf.setFont('helvetica', 'normal');
      pdf.setTextColor(55, 65, 81);
      pdf.text(descLines, margin + 4, descTableY + 5);

      yPosition = descTableY + descTableHeight + 10;
    }

    // Items Table - Compact design
    yPosition += 3;

    // Table header - smaller
    pdf.setFillColor(5, 150, 105);
    pdf.rect(margin, yPosition - 5, contentWidth, 9, 'F');

    // Column positions - ensure they fit within page
    const descColX = margin + 5;
    const qtyColX = margin + 110;
    const priceColX = margin + 135;
    const totalColX = pageWidth - margin - 5;

    pdf.setFontSize(9);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(255, 255, 255);
    pdf.text('Description', descColX, yPosition);
    pdf.text('Qty', qtyColX, yPosition);
    pdf.text('Price', priceColX, yPosition);
    pdf.text('Total', totalColX, yPosition, { align: 'right' });
    yPosition += 9;

    // Table Items - compact
    pdf.setFontSize(9);
    pdf.setFont('helvetica', 'normal');

    invoiceData.items.forEach((item, index) => {
      if (yPosition > pageHeight - 100) {
        pdf.addPage();
        yPosition = margin;
      }

      const rowHeight = 10; // Reduced from 14

      // Table row background
      pdf.setFillColor(255, 255, 255);
      pdf.rect(margin, yPosition - 5, contentWidth, rowHeight, 'F');

      // Item description
      pdf.setTextColor(17, 24, 39);
      const descLines = pdf.splitTextToSize(item.description || '', qtyColX - descColX - 2);
      pdf.text(descLines, descColX, yPosition);

      // Quantity
      pdf.setTextColor(107, 114, 128);
      pdf.text(String(item.quantity || 0), qtyColX, yPosition);

      // Unit Price
      pdf.setTextColor(107, 114, 128);
      pdf.text(`${currencySymbol} ${parseFloat(item.unitPrice || 0).toFixed(2)}`, priceColX, yPosition, { align: 'right' });

      // Total
      pdf.setFont('helvetica', 'bold');
      pdf.setTextColor(17, 24, 39);
      pdf.text(`${currencySymbol} ${parseFloat(item.total || 0).toFixed(2)}`, totalColX, yPosition, { align: 'right' });
      pdf.setFont('helvetica', 'normal');

      // Row border
      pdf.setDrawColor(229, 231, 235);
      pdf.setLineWidth(0.15);
      pdf.line(margin, yPosition - 5 + rowHeight, margin + contentWidth, yPosition - 5 + rowHeight);

      yPosition += Math.max(descLines.length * 4, rowHeight);
    });

    // Totals Table - Very Compact
    yPosition += 15;
    if (yPosition > pageHeight - 70) {
      pdf.addPage();
      yPosition = margin;
    }

    const totalsWidth = 110;
    const totalsBoxLeft = pageWidth - margin - totalsWidth;
    const totalsBoxRight = pageWidth - margin;
    const hasFeeData = !!(invoiceData?.feeData && (invoiceData.feeData.feeApplied || invoiceData.feeData.fee || invoiceData.feeData.total || invoiceData.feeData.totalPayable));
    const totalsTableHeight = hasFeeData ? 44 : 30;

    // Totals table header
    pdf.setFillColor(5, 150, 105);
    pdf.rect(totalsBoxLeft, yPosition - 5, totalsWidth, 2, 'F');

    // Totals table body
    pdf.setFillColor(249, 250, 251);
    pdf.setDrawColor(229, 231, 235);
    pdf.setLineWidth(0.3);
    pdf.rect(totalsBoxLeft, yPosition - 3, totalsWidth, totalsTableHeight, 'FD');

    const totalsPadding = 8;
    const totalsTextLeft = totalsBoxLeft + totalsPadding;
    const totalsTextRight = totalsBoxRight - totalsPadding;

    // Subtotal row
    const subtotalY = yPosition + 3;
    pdf.setDrawColor(229, 231, 235);
    pdf.setLineWidth(0.2);
    pdf.line(totalsBoxLeft + 5, subtotalY + 7, totalsBoxRight - 5, subtotalY + 7);

    pdf.setFontSize(9);
    pdf.setFont('helvetica', 'normal');
    pdf.setTextColor(107, 114, 128);
    pdf.text('Subtotal', totalsTextLeft, subtotalY + 1);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(17, 24, 39);
    pdf.text(`${currencySymbol} ${parseFloat(invoiceData.subtotal || 0).toFixed(2)}`, totalsTextRight, subtotalY + 1, { align: 'right' });

    let totalY = subtotalY + 11;
    if (hasFeeData) {
      const feeValue = invoiceData.feeData.feeApplied || invoiceData.feeData.fee || 0;
      pdf.setDrawColor(229, 231, 235);
      pdf.setLineWidth(0.2);
      pdf.line(totalsBoxLeft + 5, totalY + 7, totalsBoxRight - 5, totalY + 7);

      pdf.setFontSize(9);
      pdf.setFont('helvetica', 'normal');
      pdf.setTextColor(107, 114, 128);
      pdf.text('Fee', totalsTextLeft, totalY + 1);
      pdf.setFont('helvetica', 'bold');
      pdf.setTextColor(17, 24, 39);
      pdf.text(`${currencySymbol} ${parseFloat(feeValue || 0).toFixed(2)}`, totalsTextRight, totalY + 1, { align: 'right' });

      totalY += 11;
    }

    pdf.setFontSize(10);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(17, 24, 39);
    pdf.text(hasFeeData ? 'Total Payable' : 'Total', totalsTextLeft, totalY + 1);
    pdf.setFontSize(18);
    pdf.setTextColor(5, 150, 105);
    const totalPayable = hasFeeData
      ? (invoiceData.feeData.total || invoiceData.feeData.totalPayable || invoiceData.total || 0)
      : (invoiceData.total || 0);
    pdf.text(`${currencySymbol} ${parseFloat(totalPayable || 0).toFixed(2)}`, totalsTextRight, totalY + 1, { align: 'right' });

    // Professional footer with logo
    const footerY = pageHeight - 10;
    const borderLineY = footerY - 8;

    // Border line
    pdf.setDrawColor(229, 231, 235);
    pdf.setLineWidth(0.3);
    pdf.line(margin, borderLineY, pageWidth - margin, borderLineY);

    // "Powered by" text
    pdf.setFontSize(7);
    pdf.setFont('helvetica', 'normal');
    pdf.setTextColor(156, 163, 175);
    const poweredByText = 'Powered by';
    const textWidth = pdf.getTextWidth(poweredByText);

    // Calculate center position for footer content
    let footerContentStartX = 0;
    let footerLogoX = 0;
    let footerLogoY = 0;
    let footerLogoWidth = 0;
    let footerLogoHeight = 0;

    if (logoAdded) {
      // Use smaller logo for footer
      footerLogoWidth = logoWidth * 0.35; // Reduced from 0.45
      footerLogoHeight = logoHeight * 0.35; // Reduced from 0.45
      const spacing = 4;
      const totalFooterWidth = textWidth + spacing + footerLogoWidth;
      footerContentStartX = (pageWidth - totalFooterWidth) / 2;
      footerLogoX = footerContentStartX + textWidth + spacing;

      // Position both text and logo on the same line, below the border
      const footerTextY = borderLineY + 6;
      footerLogoY = footerTextY - footerLogoHeight + 2;

      // Add "Powered by" text
      pdf.text(poweredByText, footerContentStartX, footerTextY);

      // Add logo image
      try {
        const logoPath = '/Asset 2@1.5x (1).png';
        const imgData = await loadImageAsBase64(logoPath);
        pdf.addImage(imgData, 'PNG', footerLogoX, footerLogoY, footerLogoWidth, footerLogoHeight);
      } catch (error) {
        logger.warn('Could not load logo for footer', { error });
        pdf.text('iSmartPay', footerLogoX, footerTextY);
      }
    } else {
      // Fallback if no logo
      const poweredByFullText = 'Powered by iSmartPay';
      const fullTextWidth = pdf.getTextWidth(poweredByFullText);
      pdf.text(poweredByFullText, (pageWidth - fullTextWidth) / 2, borderLineY + 6);
    }

    // Return blob URL for preview or save file
    if (returnBlob) {
      const pdfBlob = pdf.output('blob');
      const blobUrl = URL.createObjectURL(pdfBlob);
      logger.debug('Invoice PDF generated for preview', { blobUrl });
      return blobUrl;
    }

    // Save PDF
    const fileName = `Invoice_${invoiceNumber}_${Date.now()}.pdf`;
    pdf.save(fileName);

    logger.debug('Invoice PDF generated successfully', { fileName });
    return true;
  } catch (error) {
    logger.error('Error generating PDF', { error });
    throw error;
  }
};

