/**
 * Custom Hook for Invoice Submission
 * 
 * Handles invoice submission logic including validation, payload preparation,
 * and API calls.
 */

import { useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import { apiRequest } from '@/shared/services/apiClient.js';
import { logger } from '@/shared/utils/logger.js';
import { getStoredUserId } from '@/features/disbursements/services/disbursementService.js';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { generateAccountId } from '@/features/wallet/utils/walletHelpers.js';
import { API_CONFIG } from '@/app/config/apiConfig.js';

const PROVIDER_TO_NETWORK = {
  MTN: 'mtn',
  TELECEL: 'telecel',
  'AIRTEL-TIGO': 'airteltigo',
  'AIRTELTIGO': 'airteltigo'
};

/**
 * Generate UUID for invoice reference
 */
const generateUUID = () => {
  try {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) { return crypto.randomUUID(); }
  } catch (_) { }
  const s4 = () => Math.floor((1 + Math.random()) * 0x10000).toString(16).substring(1);
  return `${s4()}${s4()}-${s4()}-${s4()}-${s4()}-${s4()}${s4()}${s4()}`;
};

const getUserIdFromStorage = () => getStoredUserId();

export const useInvoiceSubmission = () => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();

  // Use React Query mutation for invoice submission
  const submitInvoiceMutation = useMutation({
    mutationFn: async ({ payload, headers, endpoint, baseUrl }) => {
      return await apiRequest(endpoint, {
        method: 'POST',
        body: JSON.stringify(payload),
        headers,
        baseUrl
      });
    },
    invalidateQueries: [
      queryKeys.invoices.all(),
      queryKeys.dashboard.all(),
      queryKeys.reports.all(),
    ],
    onSuccess: (response) => {
      // Always use our user-friendly message instead of backend's technical message
      const userFriendlyMessage = '✓ Invoice sent successfully! Your customer will be notified shortly.';

      // Handle different response formats
      const isSuccess = (response?.Status === 'Success' || response?.status === 'success' || response?.ResponseCode === '0000');
      const hasData = response?.Data || response?.data || response?.details;

      // Handle different response formats
      if (response && isSuccess && hasData) {
        success(userFriendlyMessage);
        const data = response?.Data || response?.data || {};
        return { success: true, transactionId: data.transactionId || data.id, response };
      } else if (response && response.details) {
        const errorMsg = response.details || response.message || 'Failed to send invoice. Please try again.';
        showError(errorMsg);
        return { success: false, error: errorMsg };
      } else if (response && response.ResponseCode && response.ResponseCode !== '0000') {
        const errorMsg = response?.Data?.message || response?.message || 'Failed to send invoice. Please try again.';
        showError(errorMsg);
        return { success: false, error: errorMsg };
      } else if (response && (response.error || response.Error)) {
        const errorMsg = response.error || response.Error || response.message || 'Failed to send invoice. Please try again.';
        showError(errorMsg);
        return { success: false, error: errorMsg };
      } else {
        // Fallback success message
        success(userFriendlyMessage);
        return { success: true, response };
      }
    },
    onError: (error, variables) => {
      logger.error('Invoice submission failed', { error, payload: variables.payload });
      const errorMessage = error?.message || t('invoiceCreationFailed', { ns: 'invoicing', defaultValue: 'Failed to create invoice.' });
      showError(errorMessage);
      return { success: false, error: errorMessage };
    },
  });

  const prepareInvoicePayload = useCallback((invoiceData) => {
    const cleanedCustPhoneLocal = invoiceData.customerPhone ? cleanNumberForBackend(invoiceData.customerPhone.trim()) : '';
    const cleanedCustCountry = invoiceData.customerPhoneCountryCode ? cleanNumberForBackend(invoiceData.customerPhoneCountryCode) : '';
    const customerFullPhone = cleanedCustPhoneLocal ? `${cleanedCustCountry}${cleanedCustPhoneLocal}` : '';

    // Validate required fields
    if (!customerFullPhone) {
      showError(t('customerPhoneRequired', { ns: 'invoicing', defaultValue: 'Customer phone number is required.' }));
      return null;
    }

    const provider = invoiceData.provider;
    const channel = invoiceData.channel || 'MOMO';
    const network = channel === 'BANK'
      ? (provider || '').toLowerCase().replace('-', '')
      : (PROVIDER_TO_NETWORK[provider] || (provider || '').toLowerCase().replace('-', ''));
    const referenced = generateUUID();
    const AccountId = generateAccountId();
    const recipientId = getUserIdFromStorage();

    // Prepare items array for the payload
    const items = (invoiceData.items || []).map(item => ({
      description: item.description || '',
      quantity: parseFloat(item.quantity) || 0,
      unitPrice: parseFloat(item.unitPrice) || 0,
      total: parseFloat(item.total) || 0
    }));
    const descriptionNote = (invoiceData.description || '').trim();
    const amountValue = (parseFloat(invoiceData.total) || 0).toFixed(2);

    const payload = {
      referenceid: referenced,
      paymentType: 'invoice',
      amount: amountValue,
      currency: invoiceData.currency || 'GHS',
      narration: descriptionNote,
      items: items,
      customer: {
        firstName: invoiceData.firstName || '',
        lastName: invoiceData.lastName || '',
        phoneNumber: customerFullPhone,
        email: invoiceData.customerEmail || '',
        network: network
      }
    };

    const headers = {
      'X-Skip-Auth': '1',
      'Content-Type': 'application/json'
    };

    if (recipientId) {
      headers['recipientId'] = String(recipientId);
      logger.debug('Attached recipient ID header', { recipientId });
    }
    const endpoint = channel === 'BANK' ? '/bank-collection' : '/momo-collection';
    const baseUrl = API_CONFIG.COLLECTION_BASE_URL;

    return { payload, headers, endpoint, baseUrl };
  }, [showError, t]);

  const submitInvoice = useCallback(async (invoiceData) => {
    const prepared = prepareInvoicePayload(invoiceData);
    if (!prepared) {
      return { success: false };
    }

    const { payload, headers, endpoint, baseUrl } = prepared;

    // Use mutation to submit invoice
    const response = await submitInvoiceMutation.mutateAsync({ payload, headers, endpoint, baseUrl });

    // Check for success in various response formats and return consistent format
    if (response && response.Status === 'Success' && response.Data) {
      return { success: true, transactionId: response.Data.transactionId, response };
    } else if (response && response.details) {
      return { success: false, error: response.details || response.message };
    } else if (response && response.ResponseCode && response.ResponseCode !== '0000') {
      return { success: false, error: response?.Data?.message || response?.message };
    } else if (response && (response.error || response.Error)) {
      return { success: false, error: response.error || response.Error || response.message };
    } else if (response) {
      // If we got a response without error indicators, consider it success
      return { success: true, response };
    } else {
      return { success: false, error: 'Unknown error occurred' };
    }
  }, [prepareInvoicePayload, submitInvoiceMutation]);

  return {
    submitInvoice,
    prepareInvoicePayload,
  };
};

