import { z } from 'zod';
import { trimAndRequire, phoneNumberSchema, numericString } from './helpers';

/**
 * Creates a Zod schema for invoice validation
 * @param {Function} t - Translation function from react-i18next
 * @returns {z.ZodSchema} Invoice validation schema
 */
export const createInvoiceSchema = (t) => {
  return z
    .object({
      firstName: trimAndRequire(
        t('firstNameRequired', { ns: 'invoicing' })
      ).max(100, t('firstNameTooLong', { ns: 'invoicing' })),
      lastName: trimAndRequire(
        t('lastNameRequired', { ns: 'invoicing' })
      ).max(100, t('lastNameTooLong', { ns: 'invoicing' })),
      customerEmail: z
        .string()
        .trim()
        .min(1, t('customerEmailRequired', { ns: 'invoicing', defaultValue: 'Customer email is required' }))
        .refine(
          (val) => {
            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            return emailRegex.test(val);
          },
          { message: t('customerEmailInvalid', { ns: 'invoicing', defaultValue: 'Please enter a valid email address' }) }
        )
        .refine(
          (val) => {
            return val.length <= 255;
          },
          { message: t('customerEmailTooLong', { ns: 'invoicing', defaultValue: 'Email must be 255 characters or less' }) }
        ),
      customerPhoneCountryCode: z.string().trim().optional(),
      customerPhone: z
        .string()
        .trim()
        .min(1, t('phoneNumberRequired', { ns: 'invoicing' }))
        .refine(
          (val, ctx) => {
            const numericMessage = t('phoneNumberInvalid', { ns: 'invoicing' });
            const lengthMessage = t('phoneNumberLength', { ns: 'invoicing' });
            const phoneSchema = phoneNumberSchema(numericMessage, lengthMessage);
            const result = phoneSchema.safeParse(val);
            if (!result.success) {
              ctx.addIssue({
                code: z.ZodIssueCode.custom,
                message: result.error.errors[0].message,
              });
              return false;
            }
            return true;
          },
          { message: t('phoneNumberInvalid', { ns: 'invoicing' }) }
        ),
      payee_note: z
        .string()
        .trim()
        .max(1000, t('payeeNoteTooLong', { ns: 'invoicing' }))
        .optional(),
      description: z
        .string()
        .trim()
        .max(1000, t('descriptionTooLong', { ns: 'invoicing' }))
        .optional(),
      channel: z.enum(['MOMO', 'BANK']).optional(),
      provider: z.string().trim().optional(),
      items: z
        .array(
          z.object({
            description: trimAndRequire(
              t('itemDescriptionRequired', { ns: 'invoicing' })
            ).max(200, t('itemDescriptionTooLong', { ns: 'invoicing' })),
            quantity: z
              .union([z.number(), z.string()])
              .transform((val) => {
                const num = typeof val === 'string' ? parseFloat(val) : val;
                return isNaN(num) ? 0 : num;
              })
              .refine((val) => val > 0, {
                message: t('quantityMustBePositive', { ns: 'invoicing' }),
              })
              .refine((val) => val <= 1000000, {
                message: t('quantityTooLarge', { ns: 'invoicing' }),
              }),
            unitPrice: z
              .union([z.number(), z.string()])
              .transform((val) => {
                const num = typeof val === 'string' ? parseFloat(val) : val;
                return isNaN(num) ? 0 : num;
              })
              .refine((val) => val > 0, {
                message: t('unitPriceMustBePositive', { ns: 'invoicing', defaultValue: 'Unit price must be greater than 0' }),
              })
              .refine((val) => val <= 1000000000, {
                message: t('unitPriceTooLarge', { ns: 'invoicing' }),
              }),
            total: z.number().optional(),
          })
        )
        .min(1, t('atLeastOneItemRequired', { ns: 'invoicing' })),
      subtotal: z.number().optional(),
      taxAmount: z
        .union([z.number(), z.string()])
        .transform((val) => {
          const num = typeof val === 'string' ? parseFloat(val) : val;
          return isNaN(num) ? 0 : num;
        })
        .refine((val) => val >= 0, {
          message: t('taxAmountMustBeNonNegative', { ns: 'invoicing' }),
        })
        .optional(),
      total: z.number().optional(),
      currency: trimAndRequire(t('currencyRequired', { ns: 'invoicing' })),
      saveDraft: z.boolean().optional(),
      sendInvoice: z.boolean().optional(),
    })
    .superRefine((data, ctx) => {
      // Validate phone country code if phone is provided
      if (data.customerPhone && data.customerPhone.trim() && !data.customerPhoneCountryCode) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('phoneCountryCodeRequired', { ns: 'invoicing' }),
          path: ['customerPhoneCountryCode'],
        });
      }
      
      // Validate provider if MOMO channel is selected
      if (data.channel === 'MOMO' && (!data.provider || data.provider.trim() === '')) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('providerRequired', { ns: 'invoicing', defaultValue: 'Provider is required for mobile money transfers' }),
          path: ['provider'],
        });
      }
      

    });
};

