import React, { useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { CURRENCIES } from '@/features/invoicing/constants';

const InvoicePreviewModal = ({ isOpen, onClose, onConfirm, invoiceData, feeData, isCheckingFee, isSubmitting }) => {
    const { t } = useTranslation();

    // Prevent scrolling when modal is open
    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = 'unset';
        }
        return () => {
            document.body.style.overflow = 'unset';
        };
    }, [isOpen]);

    if (!isOpen) { return null; }

    const getCurrencySymbol = () => {
        const currency = CURRENCIES.find(c => c.code === invoiceData.currency);
        return currency ? currency.symbol : 'GH₵';
    };

    const currencySymbol = getCurrencySymbol();
    const invoiceNumber = `INV-${Date.now().toString().slice(-8)}`;

    return createPortal(
        <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            backgroundColor: 'rgba(0, 0, 0, 0.6)',
            backdropFilter: 'blur(8px)',
            WebkitBackdropFilter: 'blur(8px)',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            zIndex: 1000,
            padding: '20px'
        }}>
            <div style={{
                backgroundColor: '#ffffff',
                borderRadius: '16px',
                width: '100%',
                maxWidth: '700px',
                maxHeight: '90vh',
                display: 'flex',
                flexDirection: 'column',
                boxShadow: '0 20px 60px rgba(0, 0, 0, 0.3)',
                animation: 'slideUp 0.3s ease-out',
                border: '1px solid #e5e7eb'
            }}>
                {/* Header */}
                <div style={{
                    padding: '24px 32px',
                    borderBottom: '2px solid #f3f4f6',
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    backgroundColor: '#f9fafb'
                }}>
                    <div>
                        <h3 style={{ margin: 0, fontSize: '1.5rem', fontWeight: '700', color: '#111827' }}>
                            {t('invoicePreview', { ns: 'invoicing', defaultValue: 'Invoice Preview' })}
                        </h3>
                        <p style={{ margin: '4px 0 0 0', fontSize: '0.875rem', color: '#6b7280' }}>
                            {invoiceNumber}
                        </p>
                    </div>
                    <button
                        onClick={onClose}
                        style={{
                            background: 'none',
                            border: 'none',
                            cursor: 'pointer',
                            color: '#9ca3af',
                            padding: '8px',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            borderRadius: '8px',
                            transition: 'all 0.2s'
                        }}
                        onMouseEnter={(e) => {
                            e.currentTarget.style.backgroundColor = '#f3f4f6';
                            e.currentTarget.style.color = '#374151';
                        }}
                        onMouseLeave={(e) => {
                            e.currentTarget.style.backgroundColor = 'transparent';
                            e.currentTarget.style.color = '#9ca3af';
                        }}
                    >
                        <span className="material-symbols-outlined" style={{ fontSize: '24px' }}>close</span>
                    </button>
                </div>

                {/* Content - Scrollable */}
                <div style={{
                    padding: '32px',
                    overflowY: 'auto',
                    flex: 1
                }}>
                    {/* Customer & Provider Info - Two Column */}
                    <div style={{
                        display: 'grid',
                        gridTemplateColumns: '1fr 1fr',
                        gap: '32px',
                        marginBottom: '32px',
                        paddingBottom: '32px',
                        borderBottom: '1px solid #e5e7eb'
                    }}>
                        {/* Customer Details */}
                        <div>
                            <h4 style={{
                                fontSize: '0.75rem',
                                textTransform: 'uppercase',
                                color: '#6b7280',
                                letterSpacing: '0.05em',
                                fontWeight: '600',
                                margin: '0 0 16px 0'
                            }}>
                                {t('billTo', { ns: 'invoicing', defaultValue: 'Bill To' })}
                            </h4>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                                <p style={{ margin: 0, fontWeight: '600', fontSize: '1rem', color: '#111827', lineHeight: '1.5' }}>
                                    {invoiceData.firstName} {invoiceData.lastName}
                                </p>
                                <p style={{ margin: 0, fontSize: '0.875rem', color: '#6b7280', lineHeight: '1.5' }}>
                                    {invoiceData.customerEmail}
                                </p>
                                <p style={{ margin: 0, fontSize: '0.875rem', color: '#6b7280', lineHeight: '1.5' }}>
                                    {invoiceData.customerPhoneCountryCode} {invoiceData.customerPhone}
                                </p>
                            </div>
                        </div>

                        {/* Provider & Date Info */}
                        <div>
                            <h4 style={{
                                fontSize: '0.75rem',
                                textTransform: 'uppercase',
                                color: '#6b7280',
                                letterSpacing: '0.05em',
                                fontWeight: '600',
                                margin: '0 0 16px 0'
                            }}>
                                {t('paymentDetails', { ns: 'invoicing', defaultValue: 'Payment Details' })}
                            </h4>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                    <span style={{ fontSize: '0.875rem', color: '#6b7280', minWidth: '80px', lineHeight: '1.5' }}>
                                        {t('provider', { ns: 'invoicing', defaultValue: 'Provider' })}
                                    </span>
                                    <span style={{ fontSize: '0.875rem', fontWeight: '600', color: '#111827', lineHeight: '1.5' }}>
                                        {invoiceData.provider}
                                    </span>
                                </div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                    <span style={{ fontSize: '0.875rem', color: '#6b7280', minWidth: '80px', lineHeight: '1.5' }}>
                                        {t('channel', { ns: 'invoicing', defaultValue: 'Channel' })}
                                    </span>
                                    <span style={{ fontSize: '0.875rem', fontWeight: '600', color: '#111827', lineHeight: '1.5' }}>
                                        {(invoiceData.channel || 'MOMO').toString().toUpperCase()}
                                    </span>
                                </div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                    <span style={{ fontSize: '0.875rem', color: '#6b7280', minWidth: '80px', lineHeight: '1.5' }}>
                                        {t('currency', { ns: 'invoicing', defaultValue: 'Currency' })}
                                    </span>
                                    <span style={{ fontSize: '0.875rem', fontWeight: '600', color: '#111827', lineHeight: '1.5' }}>
                                        {invoiceData.currency}
                                    </span>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Description */}
                    {invoiceData.description && (
                        <div style={{ marginBottom: '32px' }}>
                            <h4 style={{
                                fontSize: '0.75rem',
                                textTransform: 'uppercase',
                                color: '#6b7280',
                                letterSpacing: '0.05em',
                                fontWeight: '600',
                                margin: '0 0 12px 0'
                            }}>
                                {t('description', { ns: 'invoicing', defaultValue: 'Description' })}
                            </h4>
                            <p style={{
                                margin: 0,
                                fontSize: '0.875rem',
                                color: '#374151',
                                lineHeight: '1.6',
                                whiteSpace: 'pre-wrap',
                                backgroundColor: '#f9fafb',
                                padding: '12px 16px',
                                borderRadius: '8px',
                                border: '1px solid #e5e7eb'
                            }}>
                                {invoiceData.description}
                            </p>
                        </div>
                    )}

                    {/* Items Table */}
                    <div style={{ marginBottom: '24px' }}>
                        <h4 style={{
                            fontSize: '0.75rem',
                            textTransform: 'uppercase',
                            color: '#6b7280',
                            letterSpacing: '0.05em',
                            fontWeight: '600',
                            margin: '0 0 12px 0'
                        }}>
                            {t('items', { ns: 'invoicing', defaultValue: 'Items' })}
                        </h4>
                        <div style={{
                            border: '1px solid #e5e7eb',
                            borderRadius: '12px',
                            overflow: 'hidden'
                        }}>
                            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                                <thead>
                                    <tr style={{ backgroundColor: '#f9fafb' }}>
                                        <th style={{
                                            padding: '14px 16px',
                                            textAlign: 'left',
                                            fontSize: '0.75rem',
                                            fontWeight: '600',
                                            color: '#6b7280',
                                            textTransform: 'uppercase',
                                            letterSpacing: '0.05em'
                                        }}>
                                            {t('description', { ns: 'invoicing', defaultValue: 'Description' })}
                                        </th>
                                        <th style={{
                                            padding: '14px 16px',
                                            textAlign: 'center',
                                            fontSize: '0.75rem',
                                            fontWeight: '600',
                                            color: '#6b7280',
                                            textTransform: 'uppercase',
                                            letterSpacing: '0.05em',
                                            width: '80px'
                                        }}>
                                            {t('qty', { ns: 'invoicing', defaultValue: 'Qty' })}
                                        </th>
                                        <th style={{
                                            padding: '14px 16px',
                                            textAlign: 'right',
                                            fontSize: '0.75rem',
                                            fontWeight: '600',
                                            color: '#6b7280',
                                            textTransform: 'uppercase',
                                            letterSpacing: '0.05em',
                                            width: '120px'
                                        }}>
                                            {t('price', { ns: 'invoicing', defaultValue: 'Price' })}
                                        </th>
                                        <th style={{
                                            padding: '14px 16px',
                                            textAlign: 'right',
                                            fontSize: '0.75rem',
                                            fontWeight: '600',
                                            color: '#6b7280',
                                            textTransform: 'uppercase',
                                            letterSpacing: '0.05em',
                                            width: '120px'
                                        }}>
                                            {t('total', { ns: 'invoicing', defaultValue: 'Total' })}
                                        </th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {invoiceData.items.map((item, index) => (
                                        <tr key={index} style={{
                                            borderTop: '1px solid #e5e7eb',
                                            backgroundColor: index % 2 === 0 ? '#ffffff' : '#f9fafb'
                                        }}>
                                            <td style={{
                                                padding: '14px 16px',
                                                color: '#111827',
                                                fontSize: '0.875rem',
                                                lineHeight: '1.5'
                                            }}>
                                                {item.description}
                                            </td>
                                            <td style={{
                                                padding: '14px 16px',
                                                textAlign: 'center',
                                                color: '#374151',
                                                fontSize: '0.875rem',
                                                fontWeight: '500',
                                                lineHeight: '1.5'
                                            }}>
                                                {item.quantity}
                                            </td>
                                            <td style={{
                                                padding: '14px 16px',
                                                textAlign: 'right',
                                                color: '#374151',
                                                fontSize: '0.875rem',
                                                lineHeight: '1.5'
                                            }}>
                                                {currencySymbol}{parseFloat(item.unitPrice || 0).toFixed(2)}
                                            </td>
                                            <td style={{
                                                padding: '14px 16px',
                                                textAlign: 'right',
                                                fontWeight: '600',
                                                color: '#111827',
                                                fontSize: '0.875rem',
                                                lineHeight: '1.5'
                                            }}>
                                                {currencySymbol}{parseFloat(item.total || 0).toFixed(2)}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    {/* Totals */}
                    <div style={{
                        display: 'flex',
                        justifyContent: 'flex-end',
                        marginTop: '24px'
                    }}>
                        <div style={{
                            width: '100%',
                            maxWidth: '320px',
                            backgroundColor: '#f9fafb',
                            padding: '20px 24px',
                            borderRadius: '12px',
                            border: '1px solid #e5e7eb'
                        }}>
                            <div style={{
                                display: 'flex',
                                justifyContent: 'space-between',
                                alignItems: 'center',
                                marginBottom: '12px',
                                paddingBottom: '12px',
                                borderBottom: '1px solid #e5e7eb'
                            }}>
                                <span style={{
                                    color: '#6b7280',
                                    fontSize: '0.875rem',
                                    fontWeight: '500'
                                }}>
                                    {t('subtotal', { ns: 'invoicing', defaultValue: 'Subtotal' })}
                                </span>
                                <span style={{
                                    fontWeight: '600',
                                    color: '#374151',
                                    fontSize: '0.875rem'
                                }}>
                                    {currencySymbol}{parseFloat(invoiceData.subtotal || 0).toFixed(2)}
                                </span>
                            </div>
                            {isCheckingFee && (
                                <div style={{
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: 8,
                                    fontSize: '0.8rem',
                                    color: '#6b7280',
                                    marginBottom: '12px'
                                }}>
                                    <span className="material-symbols-outlined spin" style={{ fontSize: '1rem' }}>
                                        progress_activity
                                    </span>
                                    {t('calculatingFee', { ns: 'invoicing', defaultValue: 'Calculating fee...' })}
                                </div>
                            )}
                            {feeData && !isCheckingFee && (
                                <div style={{ marginBottom: '12px' }}>
                                    <div style={{
                                        display: 'flex',
                                        justifyContent: 'space-between',
                                        alignItems: 'center',
                                        marginBottom: '6px'
                                    }}>
                                        <span style={{
                                            color: '#6b7280',
                                            fontSize: '0.875rem',
                                            fontWeight: '500'
                                        }}>
                                            {t('transactionFee', { ns: 'invoicing', defaultValue: 'Transaction Fee' })}
                                        </span>
                                        <span style={{
                                            fontWeight: '600',
                                            color: '#374151',
                                            fontSize: '0.875rem'
                                        }}>
                                            {currencySymbol}{parseFloat(feeData.feeApplied || feeData.fee || 0).toFixed(2)}
                                        </span>
                                    </div>
                                    <div style={{
                                        display: 'flex',
                                        justifyContent: 'space-between',
                                        alignItems: 'center',
                                        paddingTop: '8px',
                                        borderTop: '1px solid #e5e7eb'
                                    }}>
                                        <span style={{
                                            fontSize: '0.9rem',
                                            fontWeight: '600',
                                            color: '#111827'
                                        }}>
                                            {t('totalPayable', { ns: 'invoicing', defaultValue: 'Total Payable' })}
                                        </span>
                                        <span style={{
                                            fontSize: '1rem',
                                            fontWeight: '700',
                                            color: '#059669'
                                        }}>
                                            {currencySymbol}{parseFloat(feeData.total || feeData.totalPayable || invoiceData.total || 0).toFixed(2)}
                                        </span>
                                    </div>
                                </div>
                            )}
                            <div style={{
                                display: 'flex',
                                justifyContent: 'space-between',
                                alignItems: 'center',
                                paddingTop: '4px'
                            }}>
                                <span style={{
                                    fontSize: '1.125rem',
                                    fontWeight: '700',
                                    color: '#111827'
                                }}>
                                    {t('total', { ns: 'invoicing', defaultValue: 'Total' })}
                                </span>
                                <span style={{
                                    fontSize: '1.375rem',
                                    fontWeight: '700',
                                    color: '#059669'
                                }}>
                                    {currencySymbol}{parseFloat(invoiceData.total || 0).toFixed(2)}
                                </span>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Footer */}
                <div style={{
                    padding: '20px 32px',
                    borderTop: '2px solid #f3f4f6',
                    display: 'flex',
                    justifyContent: 'flex-end',
                    gap: '12px',
                    backgroundColor: '#f9fafb'
                }}>
                    <button
                        onClick={onClose}
                        disabled={isSubmitting}
                        className="btn"
                        style={{
                            backgroundColor: '#ffffff',
                            color: '#374151',
                            border: '1px solid #d1d5db',
                            padding: '11px 24px',
                            borderRadius: '8px',
                            cursor: isSubmitting ? 'not-allowed' : 'pointer',
                            opacity: isSubmitting ? 0.7 : 1,
                            fontWeight: '500',
                            fontSize: '0.875rem',
                            transition: 'all 0.2s'
                        }}
                        onMouseEnter={(e) => {
                            if (!isSubmitting) {
                                e.currentTarget.style.backgroundColor = '#f3f4f6';
                                e.currentTarget.style.borderColor = '#9ca3af';
                            }
                        }}
                        onMouseLeave={(e) => {
                            if (!isSubmitting) {
                                e.currentTarget.style.backgroundColor = '#ffffff';
                                e.currentTarget.style.borderColor = '#d1d5db';
                            }
                        }}
                    >
                        {t('edit', { ns: 'invoicing', defaultValue: 'Edit' })}
                    </button>
                    <button
                        onClick={onConfirm}
                        disabled={isSubmitting}
                        className="btn primary"
                        style={{
                            padding: '11px 28px',
                            borderRadius: '8px',
                            cursor: isSubmitting ? 'not-allowed' : 'pointer',
                            opacity: isSubmitting ? 0.7 : 1,
                            display: 'flex',
                            alignItems: 'center',
                            gap: '8px',
                            fontWeight: '600',
                            fontSize: '0.875rem',
                            backgroundColor: '#059669',
                            border: 'none',
                            color: '#ffffff',
                            transition: 'all 0.2s'
                        }}
                        onMouseEnter={(e) => {
                            if (!isSubmitting) {
                                e.currentTarget.style.backgroundColor = '#047857';
                            }
                        }}
                        onMouseLeave={(e) => {
                            if (!isSubmitting) {
                                e.currentTarget.style.backgroundColor = '#059669';
                            }
                        }}
                    >
                        {isSubmitting ? (
                            <>
                                <span className="material-symbols-outlined spin" style={{ fontSize: '1.2rem' }}>progress_activity</span>
                                {t('sending', { ns: 'invoicing', defaultValue: 'Sending...' })}
                            </>
                        ) : (
                            <>
                                <span className="material-symbols-outlined" style={{ fontSize: '1.2rem' }}>send</span>
                                {t('confirmAndSend', { ns: 'invoicing', defaultValue: 'Confirm & Send' })}
                            </>
                        )}
                    </button>
                </div>
            </div>
        </div>,
        document.body
    );
};

export default InvoicePreviewModal;
